  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Monstera Deliciosa', 'Living room corner. Loves a chunky aroid mix.', ARRAY['aroid', 'tropical', 'easy']::text[], 'seed-plant-monstera-deliciosa.jpg', 179),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Snake Plant', 'Indestructible. Forgot it for a month, still standing.', ARRAY['succulent', 'low-light', 'starter']::text[], 'seed-plant-snake-plant.jpg', 66),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Golden Pothos', 'Trailing along the bookshelf. Cuttings root in water in a week.', ARRAY['vining', 'easy', 'propagates']::text[], 'seed-plant-golden-pothos.jpg', 105),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Fiddle Leaf Fig', 'Dramatic. Drops a leaf if I look at it wrong.', ARRAY['statement', 'fussy', 'ficus']::text[], 'seed-plant-fiddle-leaf-fig.jpg', 201),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Peace Lily', 'Tells you exactly when it needs water by flopping completely.', ARRAY['flowering', 'low-light', 'expressive']::text[], 'seed-plant-peace-lily.jpg', 353),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Aloe Vera', 'Kitchen window. Useful when I burn myself on the cast iron.', ARRAY['succulent', 'useful', 'sunny']::text[], 'seed-plant-aloe-vera.png', 308),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Spider Plant', 'Throws babies constantly. Have given six away.', ARRAY['propagates', 'easy', 'vintage']::text[], 'seed-plant-spider-plant.jpg', 101),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'ZZ Plant', 'Survives anything. Office desk champion.', ARRAY['low-light', 'drought-tolerant', 'starter']::text[], 'seed-plant-zz-plant.jpg', 44),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Rubber Plant', 'Burgundy leaves. Wipe them down monthly so they shine.', ARRAY['statement', 'ficus', 'tropical']::text[], NULL, 310),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Bird of Paradise', 'Wants to be a tree someday. Big bright window.', ARRAY['statement', 'tropical', 'sunny']::text[], NULL, 312),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Boston Fern', 'Bathroom humidity is its love language.', ARRAY['fern', 'humid', 'fussy']::text[], NULL, 141),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Philodendron Brasil', 'Variegated trailer. Climbs the moss pole eagerly.', ARRAY['vining', 'variegated', 'easy']::text[], NULL, 336),
