  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Maranta', 'Folds its leaves up at night. Polite little plant.', ARRAY['prayer-plant', 'humid', 'low-light']::text[], NULL, 17),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'String of Pearls', 'Hanging in the kitchen. Crispy if it dries out fully.', ARRAY['succulent', 'trailing', 'sunny']::text[], NULL, 310),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'String of Hearts', 'Delicate vine. Has gotten 4 feet long this year.', ARRAY['trailing', 'delicate', 'vining']::text[], NULL, 294),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Jade Plant', 'Inherited from grandma. Pruned into a tiny tree shape.', ARRAY['succulent', 'heirloom', 'easy']::text[], NULL, 78),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Echeveria', 'Rosette under the south window. Stretches if it gets shy of light.', ARRAY['succulent', 'sunny', 'rosette']::text[], NULL, 331),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Haworthia', 'Polka-dot leaves. Likes being a little neglected.', ARRAY['succulent', 'small', 'easy']::text[], NULL, 192),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Air Plant Trio', 'Three tillandsias on driftwood. Soak weekly.', ARRAY['air-plant', 'no-soil', 'small']::text[], NULL, 256),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Boston Fern (Lemon)', 'Citrusy variety on the porch. Needs constant moisture.', ARRAY['fern', 'humid', 'outdoor']::text[], NULL, 251),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Bird''s Nest Fern', 'Crispy ruffled leaves. Looks weird and I love it.', ARRAY['fern', 'low-light', 'weird']::text[], NULL, 105),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'African Violet', 'Blooms purple all winter. Bottom-water only.', ARRAY['flowering', 'vintage', 'small']::text[], NULL, 254),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Christmas Cactus', 'Blooms reliably mid-December. Hand-me-down from a coworker.', ARRAY['cactus', 'flowering', 'heirloom']::text[], NULL, 50),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Pilea Peperomioides', 'UFO leaves. Pups everywhere I look.', ARRAY['pancake-plant', 'propagates', 'trendy']::text[], NULL, 141),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Watermelon Peperomia', 'Stripes look painted on. So small, so cute.', ARRAY['peperomia', 'small', 'patterned']::text[], NULL, 27),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Hoya Carnosa', 'Waxy leaves, waiting for the first fragrant cluster of blooms.', ARRAY['hoya', 'vining', 'patient']::text[], NULL, 69),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Hoya Kerrii', 'Single-leaf cutting. Will not grow. I love him anyway.', ARRAY['hoya', 'single-leaf', 'valentine']::text[], NULL, 244),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Anthurium', 'Red waxy spathes. Loves a warm bright spot.', ARRAY['flowering', 'tropical', 'aroid']::text[], NULL, 46),
