  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Schefflera', 'Umbrella plant. Reaches for the window dramatically.', ARRAY['tropical', 'fast-grower', 'easy']::text[], NULL, 338),
  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'English Ivy', 'Trailing in the bathroom. Misted regularly.', ARRAY['vining', 'humid', 'classic']::text[], NULL, 239),
