  (gen_random_uuid(), '26c7fd30-a938-4a96-9912-575ed030206d', '4aff6e00-aff9-4329-a1a2-e487990d9b05', 'Parlor Palm', 'Works on my desk. Tolerates the office light.', ARRAY['palm', 'low-light', 'easy']::text[], NULL, 277);
